mapper.select:
SELECT d.id, d.id_site, d.id_device_type, s.`name` AS site_name, d.devicename, d.field_value_default, dp.unit, DATE_FORMAT(CONVERT_TZ(d.last_updated,"UTC", t.`value`), "%M %d, %Y %H:%i:%s %p") AS last_updated, IFNULL(d.field_value1, 0) AS power_output, IFNULL(d.energy_today, 0) AS energy_today, IFNULL(d.energy_yesterday, 0) AS energy_yesterday, IFNULL(d.energy_this_year, 0) AS energy_this_year, IFNULL(d.avg_daily_7days, 0) AS avg_daily_7days, IFNULL(d.avg_daily_last_7days, 0) AS avg_daily_last_7days, a.note, a.id_error, a.start_date, a.end_date, e.message, e.error_code, el.`name` AS error_level_name, et.`name` AS error_type_name, dt.image, el.color, el.id AS id_error_level FROM device d LEFT JOIN device_type dt ON dt.id = d.id_device_type LEFT JOIN site s ON s.id = d.id_site LEFT JOIN time_zone t ON t.id = s.id_time_zone LEFT JOIN alert a ON a.id_device = d.id AND a.`status` = 1 AND a.end_date IS NULL LEFT JOIN error e ON e.id = a.id_error LEFT JOIN error_level el ON el.id = e.id_error_level LEFT JOIN error_type et ON et.id = e.id_error_type LEFT JOIN device_group dg ON dg.id = d.id_device_group LEFT JOIN device_parameters dp ON dp.id_device_group = dg.id AND dp.slug = d.field_value_default
WHERE d.`status` = 1 AND d.is_delete = 0 AND s.`status` = 1 AND s.is_delete = 0 AND s.id_company = #{id_company}
AND s.id = #{id_site}
AND dt.id = #{id_device_type}
AND el.id = #{id_error_level}
AND et.id = #{id_error_type}
GROUP BY d.id
LIMIT ${limit} OFFSET ${offset};

SELECT s.id, SHA1(s.id) AS hash_id, AS `name`, AS `text`, AS `label`, s.is_rec_report, s.datalogger_ip, em.first_name, em.last_name, s.id_site_group, s.id_site_sub_group, s.timezone_datalogger, s.unit_type_temp, s.unit_wind_speed, s.street, s.city, s.postal_code, s.state, s.serial_number, s.mqtt_host, s.mqtt_port, s.mqtt_protocol, s.mqtt_username, s.mqtt_password, s.site_domain_type
FROM site AS s LEFT JOIN site_employee_map sem ON sem.id_site = s.id LEFT JOIN time_zone tz ON tz.id = s.id_time_zone LEFT JOIN employee em ON em.id = sem.id_employee
WHERE s.is_delete = 0 AND s.`status` = 1 AND em.id = #{id_employee} AND s.id_company = #{id_company} GROUP BY s.id ORDER BY s.`name`, s.id_company ASC;
